// n8n Code node
// Mode: Run Once for All Items
//
// Place this directly after GetClinicPdfs.
// This creates one summary item for the email body.

const inputItems = $input.all();

let totalFiles = 0;
let totalClinics = 0;

const clinicSummaries = [];
const allFiles = [];

for (const item of inputItems) {
  const json = item.json || {};

  // GetClinicPdfs returns Graph response with json.value[]
  const files = Array.isArray(json.value) ? json.value : [];

  // Try to get the clinic folder name from paired Loop item.
  // This should work when GetClinicPdfs is inside the Loop Over Items path.
  let clinicName = 'Unknown Clinic';

  try {
    clinicName = $('Start').item.json.name || clinicName;
  } catch (error) {
    // fallback only
  }

  const pdfFiles = files.filter(file => {
    const name = file.name || '';
    return name.toLowerCase().endsWith('.pdf');
  });

  totalClinics++;
  totalFiles += pdfFiles.length;

  clinicSummaries.push({
    clinic: clinicName,
    orderCount: pdfFiles.length,
  });

  for (const file of pdfFiles) {
    allFiles.push({
      clinic: clinicName,
      fileName: file.name,
      fileId: file.id,
    });
  }
}

const clinicRowsHtml = clinicSummaries
  .map(row => `
    <tr>
      <td style="padding:6px 10px;border:1px solid #ddd;">${row.clinic}</td>
      <td style="padding:6px 10px;border:1px solid #ddd;text-align:center;">${row.orderCount}</td>
    </tr>
  `)
  .join('');

const fileRowsHtml = allFiles
  .map(file => `
    <tr>
      <td style="padding:6px 10px;border:1px solid #ddd;">${file.clinic}</td>
      <td style="padding:6px 10px;border:1px solid #ddd;">${file.fileName}</td>
    </tr>
  `)
  .join('');

const emailSummaryHtml = `
<p>Hi Team,</p>

<p>The automation has identified <strong>${totalFiles}</strong> med order PDF(s) ready to send across <strong>${totalClinics}</strong> clinic folder(s).</p>

<table style="border-collapse:collapse;margin-top:10px;margin-bottom:16px;">
  <thead>
    <tr>
      <th style="padding:6px 10px;border:1px solid #ddd;text-align:left;">Clinic</th>
      <th style="padding:6px 10px;border:1px solid #ddd;text-align:center;">Orders</th>
    </tr>
  </thead>
  <tbody>
    ${clinicRowsHtml || `
      <tr>
        <td colspan="2" style="padding:6px 10px;border:1px solid #ddd;">No PDF files found.</td>
      </tr>
    `}
  </tbody>
</table>

<p><strong>Files included:</strong></p>

<table style="border-collapse:collapse;margin-top:10px;">
  <thead>
    <tr>
      <th style="padding:6px 10px;border:1px solid #ddd;text-align:left;">Clinic</th>
      <th style="padding:6px 10px;border:1px solid #ddd;text-align:left;">File Name</th>
    </tr>
  </thead>
  <tbody>
    ${fileRowsHtml || `
      <tr>
        <td colspan="2" style="padding:6px 10px;border:1px solid #ddd;">No PDF files found.</td>
      </tr>
    `}
  </tbody>
</table>
`;

const emailSummaryText = [
  `Med order summary`,
  ``,
  `Total clinics: ${totalClinics}`,
  `Total orders: ${totalFiles}`,
  ``,
  ...clinicSummaries.map(row => `${row.clinic}: ${row.orderCount} order(s)`),
].join('\n');

return [
  {
    json: {
      totalClinics,
      totalOrders: totalFiles,
      clinicSummaries,
      files: allFiles,
      emailSummaryHtml,
      emailSummaryText,
    },
  },
];

const items = $input.all();

if (!items.length) {
  throw new Error('No PDF files found to combine');
}

const first = items[0];

const output = {
  json: {
    ...first.json,
    pdfCountForZip: items.length,
    zipFileName: `${first.json.clinic}_Scripts_${first.json.startDate}.zip`,
    sourceStatus: 'PdfFilesCombinedForZip'
  },
  binary: {}
};

items.forEach((item, index) => {
  if (!item.binary?.data) {
    throw new Error(`Missing binary data on PDF item ${index + 1}`);
  }

  const binaryKey = `PDF_${index + 1}`;

  output.binary[binaryKey] = {
    ...item.binary.data,
    fileName: item.binary.data.fileName || item.json.pdfFileName || `script_${index + 1}.pdf`,
    mimeType: item.binary.data.mimeType || 'application/pdf'
  };
});

// This gives the Compression node a dynamic list of fields to zip
output.json.binaryFieldsToZip = Object.keys(output.binary).join(',');

return [output];

const zipItem = $input.first();

if (!zipItem) {
  throw new Error('No input item found from Compression');
}

const zipBinaryKeys = Object.keys(zipItem.binary ?? {});

if (!zipBinaryKeys.length) {
  throw new Error('ZIP binary not found from Compression');
}

const zipKey = zipBinaryKeys[0];
const zipBinary = zipItem.binary[zipKey];

// Pull the email summary created by ReportBuilder
let report = {};

try {
  report = $('ReportBuilder').first().json || {};
} catch (error) {
  report = {};
}

const clinic =
  report.files?.[0]?.clinic ||
  report.clinicSummaries?.[0]?.clinic ||
  zipItem.json.clinic ||
  'Unknown Clinic';

const totalOrders =
  report.totalOrders ??
  zipItem.json.pdfCountForZip ??
  0;

const todaysDate = $('Start').first().json.TodaysDate_firstItem;

const zipFileName =
  zipBinary.fileName ||
  zipItem.json.zipFileName ||
  `${clinic}_AuMedOrder_${todaysDate}.zip`;

const subject =
  `Automation - AuMedOrder - ${clinic} - ${totalOrders} Orders`;

const emailBodyHtml =
  report.emailSummaryHtml ||
  `
  <p>Hi Team,</p>
  <p>The automation has identified <strong>${totalOrders}</strong> med order PDF(s) ready to send for <strong>${clinic}</strong>.</p>
  <p>Regards,<br>Automation</p>
  `;

return [
  {
    json: {
      ...zipItem.json,
      ...report,

      clinic,
      totalOrders,
      attachmentCount: 1,
      scriptsAttachmentName: zipFileName,

      emailSubject: subject,
      emailBodyHtml,

      sourceStatus: 'ReadyToEmailAuMedOrder',
    },
    binary: {
      scripts_zip: {
        ...zipBinary,
        fileName: zipFileName,
        mimeType: zipBinary.mimeType || 'application/zip',
      },
    },
  },
];

const item = $input.first();

if (!item) {
  throw new Error('No input item found from GetClinicFoldersForDate1');
}

const dateFolderChildren = Array.isArray(item.json.value) ? item.json.value : [];

const clinicName = $('Start').item.json.name;
const clinicFolderId = $('Start').item.json.id;

const expectedLockFileName = `_AuMedOrder_COMPLETE_${clinicName}.txt`;

const lockFile = dateFolderChildren.find(child =>
  (child.name || '').toLowerCase() === expectedLockFileName.toLowerCase()
);

return [
  {
    json: {
      clinic: clinicName,
      clinicFolderId,
      expectedLockFileName,
      lockFileExists: !!lockFile,
      lockFileId: lockFile?.id || null,
      lockFileName: lockFile?.name || null,
      dateFolderId: $('Start').item.json.DateFolderIF_id_1,
      shouldProcessClinic: !lockFile,
    },
  },
];

